import{_ as n,C as r,o as e,c as s,a2 as a,b as l,w as i,a as d,E as c,a3 as u}from"./chunks/framework.B72_uj9U.js";const x=JSON.parse('{"title":"Capy — Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/capy/architecture.md","filePath":"research/agents/capy/architecture.md"}'),h={name:"research/agents/capy/architecture.md"};function p(g,t,m,b,f,y){const o=r("Mermaid");return e(),s("div",null,[t[1]||(t[1]=a('<h1 id="capy-—-architecture" tabindex="-1">Capy — Architecture <a class="header-anchor" href="#capy-—-architecture" aria-label="Permalink to &quot;Capy — Architecture&quot;">​</a></h1><blockquote><p>Cloud-based IDE with a distinctive two-agent architecture: Captain (planning) and Build (execution), running in isolated sandboxed VMs.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Capy is a <strong>cloud-based IDE platform</strong>, not a local CLI agent or editor extension. The entire development environment — code editing, agent orchestration, execution — runs in the cloud. This architectural decision enables Capy&#39;s core value proposition: parallel execution of many tasks simultaneously, each in isolated environments.</p><p>The most distinctive architectural element is the <strong>Captain/Build split</strong> — two separate agents with hard-enforced capability boundaries that handle planning and execution respectively.</p><h2 id="the-captain-build-two-agent-architecture" tabindex="-1">The Captain/Build Two-Agent Architecture <a class="header-anchor" href="#the-captain-build-two-agent-architecture" aria-label="Permalink to &quot;The Captain/Build Two-Agent Architecture&quot;">​</a></h2><p>Capy&#39;s core insight, detailed in their blog post &quot;Captain vs Build: Why We Split the AI Agent in Two&quot; (Feb 2026), is that <strong>planning and execution should be handled by different agents with non-overlapping capabilities</strong>.</p><h3 id="captain-planning-agent" tabindex="-1">Captain (Planning Agent) <a class="header-anchor" href="#captain-planning-agent" aria-label="Permalink to &quot;Captain (Planning Agent)&quot;">​</a></h3><ul><li><strong>Role</strong>: Technical architect who PLANS but never IMPLEMENTS</li><li><strong>System prompt</strong>: <em>&quot;You are a technical architect who PLANS but never IMPLEMENTS.&quot;</em></li><li><strong>Can do</strong>: Read codebases, research documentation, ask the user clarifying questions, write exhaustive specs</li><li><strong>Cannot do</strong>: Write production code, run terminal commands, push commits</li><li><strong>Output</strong>: A spec document (described as &quot;a short PRD&quot;) that fully describes the implementation task</li></ul><p>Captain&#39;s hard constraint — it literally cannot write code — forces it to produce thorough, unambiguous specifications. This is a deliberate architectural enforcement, not just a prompt instruction.</p><h3 id="build-execution-agent" tabindex="-1">Build (Execution Agent) <a class="header-anchor" href="#build-execution-agent" aria-label="Permalink to &quot;Build (Execution Agent)&quot;">​</a></h3><ul><li><strong>Role</strong>: Autonomous executor that receives specs and ships code</li><li><strong>System prompt</strong>: <em>&quot;You are an autonomous AI agent with access to an Ubuntu virtual machine to complete the user&#39;s coding and research tasks independently and asynchronously.&quot;</em></li><li><strong>Can do</strong>: Edit files, install dependencies, run tests, open pull requests, full Ubuntu VM with sudo access</li><li><strong>Cannot do</strong>: Ask the user clarifying questions mid-task</li><li><strong>Input</strong>: The spec from Captain + access to the codebase</li></ul><p>Build&#39;s hard constraint — it cannot ask questions — forces Captain to be thorough. If the spec is ambiguous, Build must make its best judgment rather than pausing for clarification.</p><h3 id="why-the-split-matters" tabindex="-1">Why the Split Matters <a class="header-anchor" href="#why-the-split-matters" aria-label="Permalink to &quot;Why the Split Matters&quot;">​</a></h3><p>Traditional single-agent systems (Claude Code, Cursor Agent, Codex) use one agent for both planning and execution. This often leads to:</p><ol><li><strong>Premature implementation</strong> — the agent starts coding before fully understanding the task</li><li><strong>Wasted iterations</strong> — ambiguities surface only after code is written, requiring multiple rounds</li><li><strong>Context pollution</strong> — planning context and execution context compete for the same window</li></ol><p>The Captain/Build split addresses all three by making the spec the mandatory interface between planning and execution.</p><h2 id="cloud-execution-model" tabindex="-1">Cloud Execution Model <a class="header-anchor" href="#cloud-execution-model" aria-label="Permalink to &quot;Cloud Execution Model&quot;">​</a></h2><h3 id="sandboxed-ubuntu-vms" tabindex="-1">Sandboxed Ubuntu VMs <a class="header-anchor" href="#sandboxed-ubuntu-vms" aria-label="Permalink to &quot;Sandboxed Ubuntu VMs&quot;">​</a></h3><p>Each task (or &quot;jam&quot;) runs in its own <strong>sandboxed Ubuntu virtual machine</strong>:</p><ul><li>Full OS environment with sudo access for the Build agent</li><li>Isolated from other tasks and other users</li><li>Can install dependencies, run builds, execute test suites</li><li>Network access for package managers and API calls</li></ul><h3 id="git-worktree-isolation" tabindex="-1">Git Worktree Isolation <a class="header-anchor" href="#git-worktree-isolation" aria-label="Permalink to &quot;Git Worktree Isolation&quot;">​</a></h3><p>Capy uses <strong>git worktrees by default</strong> to prevent merge conflicts between parallel tasks:</p><ul><li>Each task operates on its own worktree (separate working directory, shared git objects)</li><li>Multiple tasks can modify different parts of the same repository simultaneously</li><li>No risk of one task&#39;s in-progress changes interfering with another</li></ul><p>This is critical for the parallel execution model — without worktree isolation, running 25 concurrent tasks on the same repo would be chaos.</p><h3 id="parallel-execution" tabindex="-1">Parallel Execution <a class="header-anchor" href="#parallel-execution" aria-label="Permalink to &quot;Parallel Execution&quot;">​</a></h3>',26)),(e(),l(u,null,{default:i(()=>[c(o,{id:"mermaid-175",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20P%5B%22Capy%20Cloud%20Platform%22%5D%0A%20%20%20%20T1%5B%22Task%201%5CnVM%20%2B%20worktree%22%5D%0A%20%20%20%20T2%5B%22Task%202%5CnVM%20%2B%20worktree%22%5D%0A%20%20%20%20TN%5B%22Task%2025%5CnVM%20%2B%20worktree%22%5D%0A%20%20%20%20R%5B%22Shared%20Repo%5Cn(git%20objects)%22%5D%0A%0A%20%20%20%20P%20--%3E%20T1%20%26%20T2%20%26%20TN%0A%20%20%20%20T1%20%26%20T2%20%26%20TN%20--%3E%20R%0A"})]),fallback:i(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<p>The Pro plan supports up to <strong>25 concurrent jams</strong>, each with its own VM and worktree.</p><h2 id="model-layer" tabindex="-1">Model Layer <a class="header-anchor" href="#model-layer" aria-label="Permalink to &quot;Model Layer&quot;">​</a></h2><p>Capy is <strong>model-agnostic</strong> — it does not lock users into a single LLM provider:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Models</th></tr></thead><tbody><tr><td>Anthropic</td><td>Claude Opus 4.6</td></tr><tr><td>OpenAI</td><td>GPT-5.3 Codex</td></tr><tr><td>Google</td><td>Gemini 3 Pro</td></tr><tr><td>xAI</td><td>Grok 4 Fast</td></tr><tr><td>Moonshot</td><td>Kimi K2</td></tr><tr><td>Zhipu</td><td>GLM 4.7</td></tr><tr><td>Alibaba</td><td>Qwen 3 Coder</td></tr></tbody></table><p>Both Captain and Build can presumably use different models, though the exact model routing logic is not publicly documented.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li><strong>SOC 2 Type II</strong> certified (March 2026)</li><li>Per-task VM sandboxing</li><li>Enterprise plan with custom security configurations</li></ul><h2 id="limitations-of-this-analysis" tabindex="-1">Limitations of This Analysis <a class="header-anchor" href="#limitations-of-this-analysis" aria-label="Permalink to &quot;Limitations of This Analysis&quot;">​</a></h2><p>Capy is a <strong>closed-source commercial product</strong>. There is no public GitHub repository, no open-source codebase to inspect, and internal architecture details beyond what&#39;s described in marketing materials and blog posts are not available. The Captain/Build system prompt snippets come from Capy&#39;s own blog post.</p>',9))])}const C=n(h,[["render",p]]);export{x as __pageData,C as default};
